using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ─── Configuration ───────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ─── Build chat client with automatic tool invocation ────────
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new ResearchTools();
var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(tools.SearchWeb),
        AIFunctionFactory.Create(tools.SaveNote),
        AIFunctionFactory.Create(tools.GetNotes),
    ]
};

// ─── Get topic from user ─────────────────────────────────────
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a thorough research agent. Given a topic you will:
        1. Perform several web searches with varied queries to gather broad information.
        2. Save every key finding with the SaveNote tool as you go.
        3. After gathering enough information, call GetNotes to review your collected findings.
        4. Produce a well-organized summary with sections, key points, and source URLs.
        Be comprehensive yet concise.
        """),
    new(ChatRole.User, $"Research this topic and provide a detailed summary: {topic}")
];

// The UseFunctionInvocation middleware handles the full tool-call
// loop automatically — the model calls tools, results are fed back,
// and the final text answer is returned.
var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n════════════════════════════════════════");
Console.WriteLine("           RESEARCH SUMMARY");
Console.WriteLine("════════════════════════════════════════\n");
Console.WriteLine(response.Text);

// ─── Tool Definitions ────────────────────────────────────────

sealed class ResearchTools
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } }
    };

    private readonly List<string> _notes = [];

    [Description("Search the web for information on a topic. Returns result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        try
        {
            var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}"
                    + "&format=json&no_html=1&skip_disambig=1";
            var json = await Http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;
            var snippets = new List<string>();

            var abstractText = root.GetProperty("AbstractText").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
                snippets.Add($"[{abstractSource}] {abstractText} ({abstractUrl})");

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var item in topics.EnumerateArray().Take(8))
                {
                    if (item.TryGetProperty("Text", out var text) &&
                        item.TryGetProperty("FirstURL", out var firstUrl))
                    {
                        snippets.Add($"{text.GetString()} ({firstUrl.GetString()})");
                    }
                }
            }

            return snippets.Count > 0
                ? string.Join("\n\n", snippets)
                : $"No results found for '{query}'. Try a different phrasing.";
        }
        catch (Exception ex)
        {
            return $"Search error: {ex.Message}";
        }
    }

    [Description("Save an important research finding as a note for later reference.")]
    public string SaveNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        return $"Note saved. Total notes: {_notes.Count}.";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
        return string.Join("\n---\n",
            _notes.Select((n, i) => $"Note {i + 1}: {n}"));
    }
}

